是这样的，我导出聊天历史的方式是在我跟你聊天的当前页面也就是gpt官网的当前会话页面，打开浏览器控制台，输入：
```
async function dumpIndexedDB(dbName) {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(dbName);

    req.onerror = reject;

    req.onsuccess = () => {
      const db = req.result;

      const result = {};
      const storeNames = Array.from(db.objectStoreNames);

      let pending = storeNames.length;

      storeNames.forEach((storeName) => {
        const tx = db.transaction(storeName, "readonly");
        const store = tx.objectStore(storeName);
        const getAll = store.getAll();

        getAll.onsuccess = () => {
          result[storeName] = getAll.result;
          pending--;

          if (pending === 0) {
            resolve(result);
          }
        };
      });
    };
  });
}

// 自动探测 db 名
indexedDB.databases().then(async (dbs) => {
  console.log("DBs:", dbs);

  for (const db of dbs) {
    if (!db.name) continue;

    console.log("dumping:", db.name);

    const data = await dumpIndexedDB(db.name);

    console.log("result:", data);

    // 下载文件
    const blob = new Blob(
      [JSON.stringify(data, null, 2)],
      { type: "application/json" }
    );

    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `${db.name}.json`;
    a.click();
  }
});
```

然后会通过浏览器的下载能力下载所有的会话聊天，我需要删除除了当前会话之前的所有会话历史。

